const body = $input.first().json;

const userName = body.data?.user_name || 'Artist';
const userEmail = body.data?.user_email;
const lessonsCompleted = body.data?.lessons_completed || 0;
const practiceTime = body.data?.total_practice_time || 0;
const avgScore = body.data?.average_score || 0;
const achievements = body.data?.achievements || [];
const recommendations = body.data?.next_week_recommendations || [];

if (!userEmail) {
  throw new Error('No user_email in event data');
}

const practiceHours = Math.floor(practiceTime / 60);
const practiceMinutes = practiceTime % 60;
const timeStr = practiceHours > 0
  ? `${practiceHours}h ${practiceMinutes}m`
  : `${practiceMinutes} minutes`;

const achievementsStr = achievements.length > 0
  ? `\nAchievements this week:\n${achievements.map(a => `  • ${a}`).join('\n')}`
  : '';

const recStr = recommendations.length > 0
  ? `\nRecommendations for next week:\n${recommendations.map(r => `  • ${r}`).join('\n')}`
  : '';

const emailSubject = `📊 Your weekly Art Buddy progress report, ${userName}!`;

const emailBody = `Hi ${userName},

Here's your weekly progress summary:

📚 Lessons completed: ${lessonsCompleted}
⏱️  Total practice time: ${timeStr}
⭐ Average score: ${avgScore > 0 ? avgScore.toFixed(1) + '%' : 'N/A'}${achievementsStr}${recStr}

Keep up the great work! Every practice session counts.

Return to Art Buddy: https://art-buddy-frontend.onrender.com

The Art Buddy Team`;

return [{
  json: {
    user_email: userEmail,
    user_name: userName,
    emailSubject,
    emailBody
  }
}];
